```cpp
#include <iostream>
#include <fstream>
#include <string>

int main() {
    std::string wordToCount = "example";
    int count = 0;
    std::ifstream inputFile("input.txt");

    if (inputFile.is_open()) {
        std::string line;
        while (getline(inputFile, line)) {
            size_t pos = 0;
            while ((pos = line.find(wordToCount, pos)) != std::string::npos) {
                count++;
                pos += wordToCount.length();
            }
        }
        inputFile.close();
    } else {
        std::cout << "Unable to open file";
        std::exit(1);
    }

    std::cout << "The word '" << wordToCount << "' appears " << count << " times in the file." << std::endl;
    return 0;
}
